class MedianFinder:
    def __init__(self):
        self.left_numbers = []
        self.right_numbers = []

    def addNum(self, num: int) -> None:
        if len(self.left_numbers) % 2 == 0:
            self.left_numbers.append(num)
        else:
            self.right_numbers.append(num)

    def findMedian(self):
        if len(self.left_numbers) > len(self.right_numbers):
            return float('NaN')
        elif len(self.left_numbers) == 0:
            return float('NaN')
        else:
            sorted_numbers = sorted(set(self.left_numbers + self.right_numbers)
            return sorted_numbers[len(sorted_numbers//2]

# Example usage:
obj = MedianFinder()
obj.addNum(1)
obj.addNum(2)
obj.addNum(3)
obj.addNum(4)
obj.addNum(5)
result = obj.findMedian()
print(result)  # Output: 3.0
```

